diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 33b66aeaffe6..2c3165299511 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2896,12 +2896,18 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
     Value *Cond, *TVal, *FVal;
     Value *Arg = II->getArgOperand(0);
     Value *X;
+
+    // fabs (X + 0.0) --> fabs (X)
+    // This is always safe because fabs clears the sign bit.
+    if (match(Arg, m_OneUse(m_FAdd(m_Value(X), m_PosZeroFP()))) ||
+        match(Arg, m_OneUse(m_FAdd(m_PosZeroFP(), m_Value(X)))))
+      return replaceOperand(*II, 0, X);
+
     // fabs (-X) --> fabs (X)
     if (match(Arg, m_FNeg(m_Value(X)))) {
         CallInst *Fabs = Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, II);
         return replaceInstUsesWith(CI, Fabs);
     }
-
     if (match(Arg, m_Select(m_Value(Cond), m_Value(TVal), m_Value(FVal)))) {
       // fabs (select Cond, TrueC, FalseC) --> select Cond, AbsT, AbsF
       if (Arg->hasOneUse() ? (isa<Constant>(TVal) || isa<Constant>(FVal))

